/**
 * JSON Schema for HANDOFF.md frontmatter.
 * Can be exported via `handoff schema` for external tooling.
 */
export declare const HANDOFF_SCHEMA: {
    readonly $schema: "https://json-schema.org/draft/2020-12/schema";
    readonly $id: "https://github.com/sahilraut22/Handoff/blob/main/schema/handoff-v2.json";
    readonly title: "Handoff Context Frontmatter";
    readonly description: "Schema for the YAML frontmatter in HANDOFF.md files generated by handoff-cli";
    readonly type: "object";
    readonly required: readonly ["handoff_version", "session_id", "created_at", "working_dir", "changes"];
    readonly properties: {
        readonly handoff_version: {
            readonly type: "string";
            readonly description: "Semantic version of the handoff format";
            readonly pattern: "^\\d+\\.\\d+(\\.\\d+)?$";
        };
        readonly session_id: {
            readonly type: "string";
            readonly description: "Unique identifier for this handoff session";
            readonly minLength: 1;
        };
        readonly created_at: {
            readonly type: "string";
            readonly description: "ISO 8601 timestamp when the session started";
            readonly format: "date-time";
        };
        readonly duration: {
            readonly type: "string";
            readonly description: "Human-readable session duration (e.g. \"2h 30m\")";
        };
        readonly working_dir: {
            readonly type: "string";
            readonly description: "Absolute path to the project root";
            readonly minLength: 1;
        };
        readonly agent: {
            readonly type: "string";
            readonly description: "Name of the agent that generated this handoff";
        };
        readonly changes: {
            readonly type: "object";
            readonly description: "Summary counts of file changes this session";
            readonly required: readonly ["modified", "added", "deleted"];
            readonly properties: {
                readonly modified: {
                    readonly type: "integer";
                    readonly minimum: 0;
                };
                readonly added: {
                    readonly type: "integer";
                    readonly minimum: 0;
                };
                readonly deleted: {
                    readonly type: "integer";
                    readonly minimum: 0;
                };
            };
            readonly additionalProperties: false;
        };
        readonly compression: {
            readonly type: "object";
            readonly description: "Compression metadata (present when --compress was used)";
            readonly required: readonly ["enabled", "token_budget", "tokens_used"];
            readonly properties: {
                readonly enabled: {
                    readonly type: "boolean";
                };
                readonly token_budget: {
                    readonly type: "integer";
                    readonly minimum: 0;
                };
                readonly tokens_used: {
                    readonly type: "integer";
                    readonly minimum: 0;
                };
            };
            readonly additionalProperties: false;
        };
        readonly priority_files: {
            readonly type: "array";
            readonly description: "Critical/high priority files changed this session";
            readonly items: {
                readonly type: "string";
            };
        };
        readonly decisions_included: {
            readonly type: "integer";
            readonly description: "Number of architectural decisions included";
            readonly minimum: 0;
        };
    };
    readonly additionalProperties: false;
};
